cd /workspace/YatCC && python3 << 'PYEOF'
# Restore clean EmitIR.cpp - revert all debug changes
# Actually, let me just fix the specific issues I know about:
# 1. CallExpr with a function that was already declared in the module
# 2. The issue with head->type being called on FuncDecl pointer type
# 
# The key issue: In DeclRefExpr for functions, we return the llvm::Function* 
# itself. But self(obj->head->type) tries to get the type of the ASG DeclRefExpr.
# The DeclRefExpr ASG node has type set by Json2Asg::decl_ref_expr -> getty.
# For a function reference, this type should be something like "int (int)".
# But it might not have the right texp!
#
# Let me just fix the CallExpr to get the type from the head value directly:

with open('task/3/EmitIR.cpp', 'r') as f:
    content = f.read()

# Fix CallExpr to use the head's LLVM type properly  
old = '''llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  fprintf(stderr, "CallExpr: head=%p args=%zu\\n", (void*)obj->head, obj->args.size());
  auto head = self(obj->head);
  fprintf(stderr, "CallExpr: head emitted=%p\\n", (void*)head);
  auto headTy = self(obj->head->type);
  fprintf(stderr, "CallExpr: headTy=%p\\n", (void*)headTy);
  auto fty = llvm::dyn_cast<llvm::FunctionType>(headTy);
  fprintf(stderr, "CallExpr: fty=%p\\n", (void*)fty);
  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args) {
    fprintf(stderr, "CallExpr: emitting arg\\n");
    args.push_back(self(arg));
  }
  fprintf(stderr, "CallExpr: calling CreateCall\\n");
  return mCurIrb->CreateCall(fty, head, args);
}'''

new = '''llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto head = self(obj->head);
  // Get function type from the head value's LLVM type
  auto fty = llvm::dyn_cast<llvm::FunctionType>(
    llvm::cast<llvm::PointerType>(head->getType())->getPointerElementType());
  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args)
    args.push_back(self(arg));
  return mCurIrb->CreateCall(fty, head, args);
}'''

content = content.replace(old, new)

# Also remove the other debug prints
content = content.replace(
    'for (auto&& i : tu->decls) {\n    fprintf(stderr, "TU: decl name=%s\\n", i->name.c_str());\n    self(i);\n  }',
    'for (auto&& i : tu->decls)\n    self(i);'
)
content = content.replace(
    'void\nEmitIR::operator()(VarDecl* obj)\n{\n  fprintf(stderr, "VarDecl: name=%s mCurFunc=%p init=%p\\n", obj->name.c_str(), (void*)mCurFunc, (void*)obj->init);\n  // 全局变量\n  if (mCurFunc == nullptr) {',
    'void\nEmitIR::operator()(VarDecl* obj)\n{\n  // 全局变量\n  if (mCurFunc == nullptr) {'
)
content = content.replace(
    'llvm::Value*\nEmitIR::operator()(DeclRefExpr* obj)\n{\n  auto decl = obj->decl;\n  fprintf(stderr, "DeclRefExpr: decl=%p name=%s\\n", (void*)decl, decl ? decl->name.c_str() : "null");',
    'llvm::Value*\nEmitIR::operator()(DeclRefExpr* obj)\n{\n  auto decl = obj->decl;'
)
content = content.replace(
    '  fprintf(stderr, "FunctionDecl: name=%s body=%p params=%zu\\n", obj->name.c_str(), (void*)obj->body, obj->params.size());\n  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));\n  auto func = llvm::Function::Create(',
    '  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));\n  auto func = llvm::Function::Create('
)

with open('task/3/EmitIR.cpp', 'w') as f:
    f.write(content)
print("Cleaned up and fixed CallExpr")
PYEOF

